import{_ as a,o,c as n,a2 as s}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[DX / TOOLING] F-00.4 — Internacionalización (i18n) en Español","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-00.4_internacionalizacion.md","filePath":"backlog/F-00.4_internacionalizacion.md","lastUpdated":null}'),i={name:"backlog/F-00.4_internacionalizacion.md"};function t(r,e,c,d,l,p){return o(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="dx-tooling-f-00-4-—-internacionalizacion-i18n-en-espanol" tabindex="-1">[DX / TOOLING] F-00.4 — Internacionalización (i18n) en Español <a class="header-anchor" href="#dx-tooling-f-00-4-—-internacionalizacion-i18n-en-espanol" aria-label="Permalink to &quot;[DX / TOOLING] F-00.4 — Internacionalización (i18n) en Español&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-00 — Setup e Infraestructura Base</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>DX / Tooling</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire/Blade + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.3_layout_navegacion.html">F-00.3</a></td><td>Layout <code>x-layout</code> y vistas Blade base donde se aplican los strings i18n</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Should</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que toda la interfaz del panel esté en español y que los textos estén externalizados en archivos de idioma Para que sea fácil mantener o traducir la interfaz sin tocar el código de las vistas</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Archivos de idioma):</strong> Dado que se revisa la estructura del proyecto, cuando se navega a <code>resources/lang/es/</code>, entonces existen archivos de traducción organizados: <code>app.php</code> (textos generales), <code>dashboard.php</code>, <code>logs.php</code>, <code>historico.php</code>, <code>error_codes.php</code>, <code>validation.php</code> (mensajes de validación en español).</li><li>[ ] <strong>Escenario 2 (Textos en vistas):</strong> Dado que cualquier texto visible de la UI se examina en las vistas Blade, cuando se revisa el código, entonces NO hay strings de UI hardcoded — todos usan <code>__(&#39;logs.title&#39;)</code> o <code>@lang(&#39;dashboard.cards.critical&#39;)</code>.</li><li>[ ] <strong>Escenario 3 (Mensajes de validación en español):</strong> Dado que se completa un formulario con datos inválidos, cuando se muestran los errores, entonces los mensajes de validación aparecen en español (ej. &quot;El campo URL es obligatorio&quot;).</li><li>[ ] <strong>Escenario 4 (Estructura para valenciano):</strong> Dado que en el futuro se quiera añadir valenciano (<code>va</code>), cuando se crea <code>resources/lang/va/</code>, entonces la estructura es idéntica a <code>es/</code> y solo hay que traducir los strings sin tocar las vistas.</li><li>[ ] <strong>Escenario 5 (Locale configurado):</strong> Dado que se revisa <code>config/app.php</code>, cuando se inspecciona, entonces <code>&#39;locale&#39; =&gt; &#39;es&#39;</code> y <code>&#39;fallback_locale&#39; =&gt; &#39;es&#39;</code> están configurados.</li><li>[ ] <strong>Requisito Técnico:</strong> Ejecutar <code>php artisan lang:publish</code> para publicar los archivos de validación base de Laravel. Crear los archivos de dominio en <code>resources/lang/es/</code>. Configurar <code>APP_LOCALE=es</code> en <code>.env</code>. Las fechas y números también deben usar el locale <code>es</code> (Carbon::setLocale(&#39;es&#39;)).</li></ul><hr><p><strong>MoSCoW:</strong> <code>SHOULD</code><strong>Sprint:</strong> Sprint 1</p><p><strong>Notas:</strong></p><ul><li>Prioridad alta para la primera entrega visible (Sprint 1) porque afecta a TODAS las vistas.</li><li>Se recomienda crear los archivos de idioma vacíos con los keys desde el principio e irlos rellenando conforme se desarrolla cada feature.</li><li>Carbon con locale <code>es</code> formatea fechas automáticamente en español (<code>diffForHumans()</code> devuelve &quot;hace 2 horas&quot; etc.).</li></ul>',16)])])}const h=a(i,[["render",t]]);export{g as __pageData,h as default};
